void solve(int CASE)
{
	int n; cin >> n;
	string s; cin >> s; s = ' ' + s;
	var dp = Vec4<ll>(n + 1, n + 1, n + 1, 4); // [i][len][balance][state]

	dp[0][0][0][0] = 1;
	fa(i, 1, n)fa(len, 0, i - 1) {
		if (s[i] == '(') {
			fa(bal, 0, len) fa(st, 0, 3) {
				if (st == 1 or st == 2)
					dp[i][len + 1][bal + 1][st + 1] = (dp[i][len + 1][bal + 1][st + 1] + dp[i - 1][len][bal][st]) % mod;
				else 
					dp[i][len + 1][bal + 1][st] = (dp[i][len + 1][bal + 1][st] + dp[i - 1][len][bal][st]) % mod;
			}
		}
		else {
			fa(bal, 1, len) fa(st, 0, 3) {
				if (st == 0)
					dp[i][len + 1][bal - 1][st + 1] = (dp[i][len + 1][bal - 1][st + 1] + dp[i - 1][len][bal][st]) % mod;
				else
					dp[i][len + 1][bal - 1][st] = (dp[i][len + 1][bal - 1][st] + dp[i - 1][len][bal][st]) % mod;
			}
		}
		fa(bal, 0, len)fa(st, 0, 3)dp[i][len][bal][st] = (dp[i][len][bal][st] + dp[i - 1][len][bal][st]) % mod;
	}

	ll ans = 0;
	fa(len, 4, n)ans = (ans + dp[n][len][0][3] * (len - 2ll) % mod) % mod;
	cout << ans << endl;
	return;
}
